fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val graph = Array(n.toInt()) { mutableListOf<Pair<Long, Long>>() }
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val w = edge[2]
        graph[u].add(Pair(v, w))
        graph[v].add(Pair(u, w))
    }

    val parent = Array(n.toInt()) { it.toInt() }
    val rank = Array(n.toInt()) { 1 }

    fun find(u: Int): Int {
        var node = u
        while (parent[node] != node) {
            parent[node] = parent[parent[node]]
            node = parent[node]
        }
        return node
    }

    fun union(u: Int, v: Int): Boolean {
        val uRoot = find(u)
        val vRoot = find(v)
        if (uRoot == vRoot) return false
        if (rank[uRoot] < rank[vRoot]) {
            parent[uRoot] = vRoot
            rank[vRoot] += rank[uRoot]
        } else {
            parent[vRoot] = uRoot
            rank[uRoot] += rank[vRoot]
        }
        return true
    }

    val maxHeap = PriorityQueue<Long>(Comparator { a, b -> b.compareTo(a) })
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val w = edge[2]
        if (union(u, v)) {
            maxHeap.add(w)
        }
    }

    if (maxHeap.size < k) return 0
    return maxHeap.peek() ?: 0
