            rank[vRoot.toInt()] += rank[uRoot.toInt()]
        } else {
            parent[vRoot.toInt()] = uRoot
            rank[uRoot.toInt()] += rank[vRoot.toInt()]
        }
        return true
    }

    // Use a min-heap to track the maximum edge weight in each connected component
    val maxEdges = mutableListOf<Long>()
